"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["70315"],{23075(t){t.exports=JSON.parse('{"tag":{"label":"messaging","permalink":"/sysanalyst-kb.github.io/docs/tags/messaging","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":3,"items":[{"id":"integration/enterprise-integration-patterns","title":"Enterprise Integration Patterns (EIP)","description":"Enterprise Integration Patterns (EIP) \u2014 \u044D\u0442\u043E \u043A\u0430\u0442\u0430\u043B\u043E\u0433 \u0442\u0438\u043F\u043E\u0432\u044B\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0434\u043B\u044F \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441\u0438\u0441\u0442\u0435\u043C, \u043E\u043F\u0438\u0441\u0430\u043D\u043D\u044B\u0439 \u0432 \u043A\u043D\u0438\u0433\u0435 Gregor Hohpe \u0438 Bobby Woolf (2004). EIP \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0430\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u043C \u0438 \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u2014 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0448\u0438\u043D (Kafka, RabbitMQ, Azure Service Bus) \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u044E\u0442 \u044D\u0442\u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B.","permalink":"/sysanalyst-kb.github.io/docs/integration/enterprise-integration-patterns"},{"id":"integration/rabbitmq","title":"RabbitMQ \u2014 \u043E\u0447\u0435\u0440\u0435\u0434\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439","description":"RabbitMQ \u2014 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u044B\u0439 \u0431\u0440\u043E\u043A\u0435\u0440 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439. \u0420\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0442 \u043F\u0440\u043E\u0442\u043E\u043A\u043E\u043B AMQP 0-9-1. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F task queues, RPC, \u0438 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439 \u043F\u043E \u0441\u043B\u043E\u0436\u043D\u044B\u043C \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C.","permalink":"/sysanalyst-kb.github.io/docs/integration/rabbitmq"},{"id":"integration/async-message-queue","title":"\u0410\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 (Message Queue)","description":"\u0414\u043E \u0441\u0438\u0445 \u043F\u043E\u0440 \u043C\u044B \u0433\u043E\u0432\u043E\u0440\u0438\u043B\u0438 \u043E \u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u043C REST: \u043A\u043B\u0438\u0435\u043D\u0442 \u0434\u0435\u043B\u0430\u0435\u0442 \u0437\u0430\u043F\u0440\u043E\u0441 \u0438 \u0436\u0434\u0451\u0442 \u043E\u0442\u0432\u0435\u0442. \u041D\u043E \u0435\u0441\u0442\u044C \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0438, \u0433\u0434\u0435 \u0436\u0434\u0430\u0442\u044C \u043D\u0435\u043B\u044C\u0437\u044F \u0438\u043B\u0438 \u043D\u0435 \u043D\u0443\u0436\u043D\u043E. \u0414\u043B\u044F \u044D\u0442\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0430\u0441\u0438\u043D\u0445\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u043E\u0447\u0435\u0440\u0435\u0434\u0438 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439.","permalink":"/sysanalyst-kb.github.io/docs/integration/async-message-queue"}],"unlisted":false}}')}}]);